class CheckersGame:
    def __init__(self):
        self.board = [
            ["B" if (i + j) % 2 == 1 else None for i in range(8)] for j in range(8)
        ]
        self.turn = "W"
        self.setup_board()

    def setup_board(self):
        for row, line in enumerate(self.board[:3]):
            for col, _ in enumerate(line):
                if row % 2 == 0 and col % 2 == 1:
                    self.board[row][col] = "B"

        for row, line in enumerate(self.board[5:], start=5):
            for col, _ in enumerate(line):
                if row % 2 == 1 and col % 2 == 0:
                    self.board[row][col] = "R"

    def is_valid_move(self, start, end):
        row_diff = abs(end[0] - start[0])
        col_diff = abs(end[1] - start[1])

        if (self.turn == "W" and self.board[start[0]][start[1]] == "B") or (
            self.turn == "R" and self.board[start[0]][start[1]] == "R"
        ):
            if row_diff != 2 or col_diff != 2:
                return False

            intermediate = ((start[0] + end[0]) // 2, (start[1] + end[1]) // 2)
            if self.board[intermediate[0]][intermediate[1]] not in ["W", "R"]:
                return False

            if start == end:
                return False
        elif row_diff != 1 or col_diff != 1:
            return False

        if self.board[end[0]][end[1]]:
            return False

        return True

    def move_piece(self, start, end):
        if not self.is_valid_move(start, end):
            raise ValueError("Invalid move")

        intermediate = ((start[0] + end[0]) // 2, (start[1] + end[1]) // 2)
        piece = self.board[start[0]][start[1]]
        self.board[start[0]][start[1]] = None
        self.board[end[0]][end[1]] = piece

        if row_diff == 2:
            self.board[intermediate[0]][intermediate[1]] = None

        if (self.turn == "W" and end[0] == 7) or (
            self.turn == "R" and end[0] == 0
        ):
            self.board[end[0]][end[1]] = piece.upper()

        self.turn = "B" if self.turn == "W" else "W"

    def display_board(self):
        for row in self.board:
            print(" ".join(f"{cell or '.'}" for cell in row))
        print("\n")

